(()=>{"use strict";const csv=e=>{const sep=/[\t,]/;const val=/[^,\t\r\n]+/;const num=/(^|[\t,])\s*-?(?:\d+(?:\.\d+)?|\.\d+)(?=[\t,]|$)/;const lit=/(^|[\t,])\s*(?:true|false|null)(?=[\t,]|$)/i;const q=i=>({className:"quote",begin:/"/,end:/"/,contains:[{className:i,begin:/""|[^"\r\n]+/}]});const row={begin:/(?=.)/,end:/$/,contains:[q("string"),{className:"number",match:num},{className:"literal",match:lit},{className:"attr",match:val},{className:"punctuation",match:sep}]};const header={begin:/^/,end:/\r?\n|$/,contains:[q("string"),{className:"title",match:val},{className:"punctuation",match:sep}],starts:{contains:[row]}};return{name:"CSV",aliases:["comma-separated-values","tsv","tab-separated-values"],contains:[header]}};if(typeof hljs!=="undefined"&&hljs&&typeof hljs.registerLanguage==="function"){hljs.registerLanguage("csv",csv);hljs.registerLanguage("tsv",csv)}})();